/// Days in gradebook history for this course
pub async fn days_in_gradebook_history_for_this_course_page(
    client: &CoolClient,
    course_id: &str,
    next_url: Option<&str>,
) -> Result<PaginatedResponse<Day>> {
    let url = next_url.map(String::from).unwrap_or_else(|| {
        let mut path = "/api/v1/courses/:course_id/gradebook_history/days".to_string();
        path = path.replace(":course_id", course_id);
        path
    });
    client.get_paginated::<Day, ()>(&url, None::<&()>).await
}

/// Days in gradebook history for this course (auto-paginated stream)
pub fn days_in_gradebook_history_for_this_course<'a>(
    client: &'a CoolClient,
    course_id: &'a str,
) -> impl Stream<Item = Result<Day>> + 'a {
    futures::stream::unfold(Some(String::new()), move |state| async move {
        let next_url = state?;
        let url_ref = if next_url.is_empty() { None } else { Some(next_url.as_str()) };
        match days_in_gradebook_history_for_this_course_page(
            client,
            course_id,
            url_ref,
        ).await {
            Ok(page) => {
                let next = page.next_url.clone();
                let items = page.items.into_iter().map(Ok).collect::<Vec<_>>();
                Some((futures::stream::iter(items), next))
            }
            Err(e) => Some((futures::stream::iter(vec![Err(e)]), None)),
        }
    })
    .flatten()
}

