/// Details for a given date in gradebook history for this course
pub async fn details_for_given_date_in_gradebook_history_for_this_course_page(
    client: &CoolClient,
    course_id: &str,
    date: &str,
    next_url: Option<&str>,
) -> Result<PaginatedResponse<Grader>> {
    let url = next_url.map(String::from).unwrap_or_else(|| {
        let mut path = "/api/v1/courses/:course_id/gradebook_history/:date".to_string();
        path = path.replace(":course_id", course_id);
        path = path.replace(":date", date);
        path
    });
    client.get_paginated::<Grader, ()>(&url, None::<&()>).await
}

/// Details for a given date in gradebook history for this course (auto-paginated stream)
pub fn details_for_given_date_in_gradebook_history_for_this_course<'a>(
    client: &'a CoolClient,
    course_id: &'a str,
    date: &'a str,
) -> impl Stream<Item = Result<Grader>> + 'a {
    futures::stream::unfold(Some(String::new()), move |state| async move {
        let next_url = state?;
        let url_ref = if next_url.is_empty() { None } else { Some(next_url.as_str()) };
        match details_for_given_date_in_gradebook_history_for_this_course_page(
            client,
            course_id,
            date,
            url_ref,
        ).await {
            Ok(page) => {
                let next = page.next_url.clone();
                let items = page.items.into_iter().map(Ok).collect::<Vec<_>>();
                Some((futures::stream::iter(items), next))
            }
            Err(e) => Some((futures::stream::iter(vec![Err(e)]), None)),
        }
    })
    .flatten()
}

