/// Get all ePortfolios for a User (auto-paginated stream)
pub fn get_all_eportfolios_for_user<'a>(
    client: &'a CoolClient,
    user_id: &'a str,
    query_params: &'a GetAllEportfoliosForUserParams,
) -> impl Stream<Item = Result<ePortfolio>> + 'a {
    futures::stream::unfold(Some(String::new()), move |state| async move {
        let next_url = state?;
        let url_ref = if next_url.is_empty() { None } else { Some(next_url.as_str()) };
        match get_all_eportfolios_for_user_page(
            client,
            user_id,
            query_params,
            url_ref,
        ).await {
            Ok(page) => {
                let next = page.next_url.clone();
                let items = page.items.into_iter().map(Ok).collect::<Vec<_>>();
                Some((futures::stream::iter(items), next))
            }
            Err(e) => Some((futures::stream::iter(vec![Err(e)]), None)),
        }
    })
    .flatten()
}

