/// Query by account.
pub async fn query_by_account_page(
    client: &CoolClient,
    account_id: &str,
    query_params: &QueryByAccountParams,
    next_url: Option<&str>,
) -> Result<PaginatedResponse<CourseEvent>> {
    let url = next_url.map(String::from).unwrap_or_else(|| {
        let mut path = "/api/v1/audit/course/accounts/:account_id".to_string();
        path = path.replace(":account_id", account_id);
        path
    });
    client.get_paginated(&url, Some(query_params)).await
}

/// Query by account. (auto-paginated stream)
pub fn query_by_account<'a>(
    client: &'a CoolClient,
    account_id: &'a str,
    query_params: &'a QueryByAccountParams,
) -> impl Stream<Item = Result<CourseEvent>> + 'a {
    futures::stream::unfold(Some(String::new()), move |state| async move {
        let next_url = state?;
        let url_ref = if next_url.is_empty() { None } else { Some(next_url.as_str()) };
        match query_by_account_page(
            client,
            account_id,
            query_params,
            url_ref,
        ).await {
            Ok(page) => {
                let next = page.next_url.clone();
                let items = page.items.into_iter().map(Ok).collect::<Vec<_>>();
                Some((futures::stream::iter(items), next))
            }
            Err(e) => Some((futures::stream::iter(vec![Err(e)]), None)),
        }
    })
    .flatten()
}

